import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useLocation, useNavigate } from 'react-router-dom'; // Thêm import này

const CarManagement = () => {
    const [cars, setCars] = useState([]);
    const [showForm, setShowForm] = useState(false);
    const [editingCar, setEditingCar] = useState(null);
    const [formData, setFormData] = useState({
        name: '',
        brand: '',
        price: '',
        year: '',
        fuel_type: '',
        speed: '',
        image_url: '',
        description: ''
    });

    const location = useLocation(); // Lấy thông tin location
    const navigate = useNavigate(); // Dùng để xóa state sau khi xử lý xong

    useEffect(() => {
        fetchCars();
    }, []);

    // --- ĐOẠN CODE MỚI: TỰ ĐỘNG MỞ FORM SỬA NẾU CÓ TRUYỀN ID TỪ TRANG KHÁC ---
    useEffect(() => {
        // Kiểm tra xem có ID truyền sang không và danh sách xe đã load chưa
        if (location.state && location.state.editCarId && cars.length > 0) {
            
            // Tìm chiếc xe tương ứng
            const carToEdit = cars.find(c => c.id === location.state.editCarId);
            
            if (carToEdit) {
                // Gọi hàm sửa xe
                handleEdit(carToEdit);
                
                // Xóa cái ID trong bộ nhớ location đi (tránh việc refresh trang nó lại tự động mở)
                navigate('/admin/cars', { replace: true, state: {} });
            }
        }
    }, [location.state, cars, navigate]);
    // -------------------------------------------------------------------------

    const fetchCars = async () => {
        try {
            const res = await axios.get('http://localhost:5000/api/cars');
            setCars(res.data.data || res.data);
        } catch (error) {
            console.error('Lỗi tải xe:', error);
        }
    };

    const handleInputChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingCar) {
                // Sửa xe
                await axios.put(`http://localhost:5000/api/admin/cars/${editingCar.id}`, formData);
                alert('Cập nhật xe thành công!');
            } else {
                // Thêm xe mới
                await axios.post('http://localhost:5000/api/admin/cars', formData);
                alert('Thêm xe thành công!');
            }
            setShowForm(false);
            setEditingCar(null);
            setFormData({
                name: '', brand: '', price: '', year: '', 
                fuel_type: '', speed: '', image_url: '', description: ''
            });
            fetchCars();
        } catch (error) {
            alert('Lỗi: ' + (error.response?.data?.message || 'Thao tác thất bại'));
        }
    };

    const handleEdit = (car) => {
        setEditingCar(car);
        setFormData(car);
        setShowForm(true);
    };

    const handleDelete = async (id) => {
        if (window.confirm('Bạn có chắc muốn xóa xe này?')) {
            try {
                await axios.delete(`http://localhost:5000/api/admin/cars/${id}`);
                alert('Xóa xe thành công!');
                fetchCars();
            } catch (error) {
                alert('Lỗi: ' + (error.response?.data?.message || 'Xóa thất bại'));
            }
        }
    };

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginbottom: '20px' }}>
                <h1>Quản lý xe</h1>
                <button 
                    onClick={() => {
                        setEditingCar(null);
                        setFormData({
                            name: '', brand: '', price: '', year: '',
                            fuel_type: '', speed: '', image_url: '', description: ''
                        });
                        setShowForm(true);
                    }}
                    className="btn-edit"
                    style={{ padding: '10px 20px' }}
                >
                    + Thêm xe mới
                </button>
            </div>

            {showForm && (
                <div className="modal">
                    <div className="modal-content" style={{ maxWidth: '600px' }}>
                        <span className="close" onClick={() => setShowForm(false)}>&times;</span>
                        <h2>{editingCar ? 'Sửa xe' : 'Thêm xe mới'}</h2>
                        
                        <form onSubmit={handleSubmit}>
                            <div className="form-group">
                                <label>Tên xe</label>
                                <input
                                    type="text"
                                    name="name"
                                    value={formData.name}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>
                            
                            <div className="form-group">
                                <label>Hãng xe</label>
                                <input
                                    type="text"
                                    name="brand"
                                    value={formData.brand}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>
                            
                            <div className="form-group">
                                <label>Giá (VNĐ)</label>
                                <input
                                    type="number"
                                    name="price"
                                    value={formData.price}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>
                            
                            <div className="form-group">
                                <label>Năm sản xuất</label>
                                <input
                                    type="number"
                                    name="year"
                                    value={formData.year}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>
                            
                            <div className="form-group">
                                <label>Nhiên liệu</label>
                                <select
                                    name="fuel_type"
                                    value={formData.fuel_type}
                                    onChange={handleInputChange}
                                    required
                                >
                                    <option value="">Chọn loại</option>
                                    <option value="Xăng">Xăng</option>
                                    <option value="Dầu">Dầu</option>
                                    <option value="Hybrid">Hybrid</option>
                                    <option value="Điện">Điện</option>
                                </select>
                            </div>
                            
                            <div className="form-group">
                                <label>Tốc độ tối đa (km/h)</label>
                                <input
                                    type="number"
                                    name="speed"
                                    value={formData.speed}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>
                            
                            <div className="form-group">
                                <label>URL hình ảnh</label>
                                <input
                                    type="text"
                                    name="image_url"
                                    value={formData.image_url}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>
                            
                            <div className="form-group">
                                <label>Mô tả</label>
                                <textarea
                                    name="description"
                                    value={formData.description}
                                    onChange={handleInputChange}
                                    rows="4"
                                    required
                                />
                            </div>
                            
                            <button type="submit" className="auth-btn">
                                {editingCar ? 'Cập nhật' : 'Thêm mới'}
                            </button>
                        </form>
                    </div>
                </div>
            )}

            <table className="admin-table">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Ảnh</th>
                        <th>Tên xe</th>
                        <th>Hãng</th>
                        <th>Giá</th>
                        <th>Năm</th>
                        <th>Thao tác</th>
                    </tr>
                </thead>
                <tbody>
                    {cars.map(car => (
                        <tr key={car.id}>
                            <td>{car.id}</td>
                            <td>
                                <img 
                                    src={car.image_url} 
                                    alt={car.name}
                                    style={{ width: '50px', height: '50px', objectFit: 'cover' }}
                                />
                            </td>
                            <td>{car.name}</td>
                            <td>{car.brand}</td>
                            <td>{car.price?.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.')} ₫</td>
                            <td>{car.year}</td>
                            <td>
                                <button onClick={() => handleEdit(car)} className="btn-edit">
                                    Sửa
                                </button>
                                <button onClick={() => handleDelete(car.id)} className="btn-delete">
                                    Xóa
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default CarManagement;
